import SwiftUI

struct RadiationValueLabelView: View {

    let value: Decimal?
    let radiationType: RadiationType

    var valueFont: Font?
    var unitFont: Font?

    var body: some View {
        HStack(alignment: .lastTextBaseline, spacing: 4) {
            if let value {
                Text(verbatim: radiationType.scale(value: value).formattedValue)
                    .applyFont(valueFont)
                Text(radiationType.unitByValue(value: value))
                    .applyFont(unitFont)
            } else {
                Text(verbatim: "--")
                    .applyFont(valueFont)
                Text(radiationType.unit)
                    .applyFont(unitFont)
            }
        }
        .lineLimit(1)
    }
}

private extension View {
    @ViewBuilder
    func applyFont(_ font: Font?) -> some View {
        if let font {
            self.font(font)
        } else {
            self
        }
    }
}

